#include <bits/stdc++.h>
using namespace std;
int n,q,b[1003];
int main(){
    cin>>n>>q;
    for(int i=1;i<=n;i++)cin>>b[i];
    while(q--){
        int f,t,sum=0;
        cin>>f>>t;
        for(int i=1;i<=n;i++)sum+=(b[i]%int(pow(10,f))==t);
        cout<<sum<<endl;
    }
    return 0;
}
